// src/services/StudyMethodService.js
import StudyMethodRepository from '../repositories/StudyMethodRepository';

type MethodListFilters = { search?: string; category?: string };

const StudyMethodService = {
  async getAllMethods(filters: MethodListFilters = {}) {
    const { search, category } = filters;

    if (search && search.trim()) {
      return await StudyMethodRepository.search(search.trim());
    }

    if (category && category !== 'all') {
      return await StudyMethodRepository.getByCategory(category);
    }

    return await StudyMethodRepository.getAll();
  },

  async getMethodById(id) {
    return await StudyMethodRepository.getById(id);
  },

  async createMethod(methodData, userId) {
    const { name, description, category, duration_minutes, benefits, ideal_for } = methodData;

    if (!name || !description || !category) {
      throw new Error('Nome, descrição e categoria são obrigatórios.');
    }

    return await StudyMethodRepository.create({
      name,
      description,
      category,
      duration_minutes: duration_minutes || null,
      benefits: benefits || [],
      ideal_for: ideal_for || '',
      created_by: userId,
      created_at: new Date().toISOString()
    });
  },

  async updateMethod(id, methodData) {
    const { name, description, category, duration_minutes, benefits, ideal_for } = methodData;

    if (!name || !description || !category) {
      throw new Error('Nome, descrição e categoria são obrigatórios.');
    }

    return await StudyMethodRepository.update(id, {
      name,
      description,
      category,
      duration_minutes,
      benefits,
      ideal_for
    });
  },

  async deleteMethod(id) {
    return await StudyMethodRepository.remove(id);
  },

  getCategories() {
    return [
      { value: 'all', label: 'Todas as categorias' },
      { value: 'focus', label: 'Técnica de Foco' },
      { value: 'organization', label: 'Organização' },
      { value: 'revision', label: 'Revisão' },
      { value: 'memorization', label: 'Memorização' },
      { value: 'reading', label: 'Leitura' },
      { value: 'practice', label: 'Prática' }
    ];
  },

  getCategoryLabel(value) {
    const cats = this.getCategories();
    return cats.find(c => c.value === value)?.label || value;
  }
};

export default StudyMethodService;
